VkIndirectExecutionSetEXT indirectExecutionSet = VK_NULL_HANDLE;
uint32_t executionSetWriteCount = 0;
VkWriteIndirectExecutionSetPipelineEXT* executionSetWrites = nullptr;

vkUpdateIndirectExecutionSetPipelineEXT(
    device,
    indirectExecutionSet,
    executionSetWriteCount,
    executionSetWrites
);

VkDevice device = VK_NULL_HANDLE;
VkIndirectExecutionSetEXT indirectExecutionSet = VK_NULL_HANDLE;
uint32_t executionSetWriteCount = 0;
VkWriteIndirectExecutionSetShaderEXT* executionSetWrites = nullptr;

vkUpdateIndirectExecutionSetShaderEXT(
