VkDevice device = VK_NULL_HANDLE;
VkVideoSessionParametersKHR videoSessionParameters = VK_NULL_HANDLE;
VkVideoSessionParametersUpdateInfoKHR updateInfo = {};
updateInfo.sType = VK_STRUCTURE_TYPE_VIDEO_SESSION_PARAMETERS_UPDATE_INFO_KHR;

VkResult result = vkUpdateVideoSessionParametersKHR(
    device,
    videoSessionParameters,
    &updateInfo
);

if (result == VK_SUCCESS) {
    // تمت العملية بنجاح ويمكن متابعة العمل بعد vkUpdateVideoSessionParametersKHR
} else {
    // عالج رمز الخطأ أو أعد تهيئة الموارد المطلوبة
}
